import collections

class MyHashSet:
    def __init__(self):
        self._capacity = 16
        self._buckets = [[] for _ in range(self._capacity)]
        self._size = 0
        self._load_factor_threshold = 0.75

    def _hash(self, key):
        return hash(key)

    def _get_bucket_index(self, key):
        return self._hash(key) % self._capacity

    def add(self, key) -> None:
        if (self._size + 1) / self._capacity > self._load_factor_threshold:
            self._resize()

        bucket_index = self._get_bucket_index(key)
        bucket = self._buckets[bucket_index]

        if key not in bucket:
            bucket.append(key)
            self._size += 1

    def remove(self, key) -> None:
        bucket_index = self._get_bucket_index(key)
        bucket = self._buckets[bucket_index]

        if key in bucket:
            bucket.remove(key)
            self._size -= 1

    def contains(self, key) -> bool:
        bucket_index = self._get_bucket_index(key)
        bucket = self._buckets[bucket_index]
        return key in bucket

    def _resize(self):
        old_buckets = self._buckets
        self._capacity *= 2
        self._buckets = [[] for _ in range(self._capacity)]
        self._size = 0

        for bucket in old_buckets:
            for key in bucket:
                new_bucket_index = self._get_bucket_index(key)
                self._buckets[new_bucket_index].append(key)
                self._size += 1

    def __len__(self) -> int:
        return self._size

    def __contains__(self, key) -> bool:
        return self.contains(key)

    def __str__(self) -> str:
        elements = []
        for bucket in self._buckets:
            elements.extend(bucket)
        try:
            return "{" + ", ".join(map(str, sorted(elements))) + "}"
        except TypeError:
            return "{" + ", ".join(map(str, elements)) + "}"

    def __repr__(self) -> str:
        return self.__str__()
